sys_acl.script:
// ACL: L1 agents can only read incidents assigned to their own groups
// This works alongside the before query business rule

// Admin can always read
if (gs.hasRole('admin')) {
  return true;
}

// L2 agents can read all incidents
if (gs.hasRole('itsm_l2_agent')) {
  return true;
}

// L3 agents can read incidents assigned to their groups
if (gs.hasRole('itsm_l3_agent')) {
  var userGroups = [];
  var gr = new GlideRecord('sys_user_grmember');
  gr.addQuery('user', gs.getUserID());
  gr.query();
  while (gr.next()) {
    userGroups.push(gr.getValue('group'));
  }
  if (userGroups.indexOf(current.assignment_group.toString()) >= 0) {
    return true;
  }
  return false;
}

// Normal users can only read incidents they created
if (!gs.hasRole('itsm_l1_agent') && !gs.hasRole('itsm_l2_agent') && !gs.hasRole('itsm_l3_agent')) {
  if (current.caller_id.toString() === gs.getUserID()) {
    return true;
  }
  return false;
}

// L1 agents - checked by the before query business rule
if (gs.hasRole('itsm_l1_agent')) {
  var myGroups = [];
  var member = new GlideRecord('sys_user_grmember');
  member.addQuery('user', gs.getUserID());
  member.query();
  while (member.next()) {
    myGroups.push(member.getValue('group'));
  }
  if (myGroups.indexOf(current.assignment_group.toString()) >= 0) {
    return true;
  }
  return false;
}

return true;
